async function execute(browser: WebFlowBrowserAPI, params: FlowParams): Promise<WebFlowResult> {
    const cartButton = await browser.extractComponent<{ label: string; detailsLinkSelector: string }>(
        {
            typeName: 'ShoppingCartButton',
            schema: '{ label: string; detailsLinkSelector: string; }'
        }
    );
    if (!cartButton || !cartButton.detailsLinkSelector) {
        throw new Error('Could not find shopping cart button on this page');
    }
    await browser.click(cartButton.detailsLinkSelector);
    await browser.awaitPageLoad();
    const cartDetails = await browser.extractComponent<{ storeName: string; totalAmount: string; productsInCart?: { name: string; price: string; quantity?: string }[] }>(
        {
            typeName: 'ShoppingCartDetails',
            schema: '{ storeName: string; totalAmount: string; productsInCart?: { name: string; price: string; quantity?: string; }[]; }'
        }
    );
    return { success: true, message: 'Viewing shopping cart', data: cartDetails };
}
